// Process inbound lead from form, CRM, or website contact
const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    source: body.source || 'inbound',
    name: body.name || body.contact_name || '',
    email: body.email || body.contact_email || '',
    phone: body.phone || '',
    company: body.company || body.company_name || '',
    industry: body.industry || '',
    employeeCount: body.employee_count || body.size || '',
    message: body.message || body.inquiry || '',
    website: body.website || '',
    receivedAt: new Date().toISOString()
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let scoring;
try {
  const match = content.match(/\{[\s\S]*\}/);
  scoring = JSON.parse(match ? match[0] : content);
} catch {
  scoring = { score: 50, tier: 'warm', reasoning: 'Unable to parse scoring response', personalization_angle: '' };
}

const lead = $('Parse Lead Data').first().json;

return [{
  json: {
    ...lead,
    icpScore: scoring.score || 50,
    tier: scoring.tier || 'warm',
    reasoning: scoring.reasoning || '',
    personalizationAngle: scoring.personalization_angle || ''
  }
}];

